import json, pathlib
ROOT = pathlib.Path(__file__).parent.parent

def load_comm(source, book):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    if p.exists():
        return json.loads(p.read_text())
    return {}

def save_comm(source, book, data):
    p = ROOT / 'data' / 'commentary' / source / f'{book}.json'
    p.parent.mkdir(parents=True, exist_ok=True)
    p.write_text(json.dumps(data, ensure_ascii=False, indent=None))
    print(f'  wrote {p.relative_to(ROOT)}')

def merge_comm(existing, new_data):
    for ch, verses in new_data.items():
        if ch not in existing:
            existing[ch] = {}
        for v, html in verses.items():
            if v not in existing[ch]:
                existing[ch][v] = html

ISAIAH = {'51': {'1': "<p>YHWH opens the oracle to those who pursue <em>tsedaqah</em> — the same righteousness he will enact. The call to look back to Abraham the single ancestor who became many grounds hope: the same creative fidelity that multiplied one person can restore a decimated community. <em>Tsedaqah</em> (disp 3) is not merely personal virtue but the right-ordering YHWH exercises on behalf of the covenant community; here it is simultaneously what the exiles are called to pursue and what YHWH himself is about to execute (vv 5-8). The rock/quarry metaphor underscores that Israel's identity is carved from a specific history, not from present numerical strength.</p>", '2': '<p>Sarah is named alongside Abraham — unusual and striking. She gave birth to the one child who became many; the barren mother figure anticipates 54:1. The logic of vv 1-2 is: if YHWH could populate a nation from a single sterile couple, he can repopulate Zion from scattered exiles. History becomes the warrant for eschatological hope.</p>', '3': "<p>YHWH will comfort (<em>naham</em>) Zion's ruins, transforming wilderness into Eden and desert into the LORD's garden. The Eden echo is deliberate: restoration is not merely return to pre-exile conditions but to original creational fullness. Joy, gladness, thanksgiving, and singing describe the transformed community — the same joy vocabulary recurs at 51:11 and 52:9, binding this oracle into a single movement.</p>", '4': "<p><em>Torah</em> (instruction/law) will go out from YHWH and he will establish <em>mishpat</em> (justice/judgment) as a light for peoples. The universalizing scope — coastlands wait for YHWH's arm — shows that Israel's restoration is not ethnic favoritism but the means of worldwide justice. This torah-from-YHWH language echoes Isa 2:3 and anticipates the new-covenant internalization of 55:3.</p>", '5': "<p><em>Tsedaqah</em> (righteousness, disp 3) and <em>yeshuah</em> (salvation) are paired as near-synonyms for what YHWH is about to release. His arm will rule the nations — the same arm invoked at 51:9 in the exodus prayer and revealed to Isaiah's messenger at 53:1. The arm of YHWH is the agent of both creation (51:9-10) and redemption, cementing the pattern that YHWH's saving act recapitulates his creative act.</p>", '6': "<p>Heavens and earth — the two most permanent things in the ancient world — will vanish like smoke and wear out like a garment, but YHWH's <em>yeshuah</em> (salvation) and <em>tsedaqah</em> will not fail. The contrast establishes that Israel's trust must rest not on present political or cosmic structures but on YHWH's covenant fidelity. <em>Olam</em> (everlasting, disp 3) salvation and righteousness: YHWH's saving acts are not temporary; they participate in the eternal dimension of his character.</p>", '7': "<p>Those who know righteousness and have YHWH's <em>torah</em> in their hearts are addressed — the same internalized instruction that 55:3 and Jer 31:33 promise. Fear of human reproach is the specific temptation being countered: the exiles are being mocked by Babylonian overlords. YHWH counters it with the insect-vs-eternity contrast of v 8.</p>", '8': "<p>The moth-and-worm devouring of human opponents parallels the garment-wearing-out of v 6 — the same fabric metaphor applied to oppressors. In contrast, YHWH's <em>tsedaqah</em> will endure <em>le'olam</em> (for ever) and his <em>yeshuah</em> for all generations. The repetition from v 6 is intentional: YHWH's eternal righteousness is the ground for not fearing finite human opposition.</p>", '9': "<p>The exiles cry to YHWH's arm to wake up — inverting the earlier divine calls to Israel to wake up (vv 1, 4, 7). The arm is asked to reclothe itself in strength as in the ancient days, invoking Rahab (a chaos sea-dragon) and the dragon of exodus mythology. The prayer identifies YHWH's past acts — creation-by-combat, exodus — as the pattern for the coming deliverance. <em>Qedem</em> (ancient times) and <em>dorot olam</em> (generations of old) establish a deep temporal continuity of YHWH's power.</p>", '10': '<p>The rhetorical question recalls the Red Sea crossing: the sea dried up, the deep split, and the ransomed walked through. The theology: the God who made a road through the sea for the first exodus can open a road through the Babylonian wilderness for the second. This verse is the theological pivot the exiles invoke as the ground for their prayer — his past act guarantees his future act.</p>', '11': '<p>Verbatim repetition of 35:10 — a deliberate cross-reference. The ransomed (<em>peduyei YHWH</em>) will return to Zion with singing, crowned with <em>simhat olam</em> (everlasting joy, <em>olam</em> disp 3). Sorrow and sighing flee. The echo of chapter 35 signals that the restoration oracle corpus is a unified whole; chapter 51 gathers and restates the most vivid images of chapters 35-40 as the exilic moment arrives.</p>', '12': '<p>YHWH asserts in the first person: <em>anochi anochi</em> — I, I myself, am the one who comforts you. The doubling is emphatic. The rebuke follows immediately: who are you to fear a mortal who will die, who will become grass? The <em>nefesh</em> (soul/self, disp 3) of the oppressor is as fragile as vegetation. The fear of human power is irrationality in the face of the eternal comforter.</p>', '13': "<p>The accusation: Israel has forgotten YHWH the Maker who stretched out the heavens and laid the earth's foundations — and stands in continual dread of the oppressor's fury. But the oppressor's fury is finite: the cowering prisoner (v 14) will be free. The forgetting of YHWH is not intellectual but practical — their daily terror reveals where their functional trust lies.</p>", '14': '<p>The cowering prisoner — the exiled community — will quickly be released and will not die in a dungeon or lack food. The promise is concrete and immediate: this is not distant eschatology but near deliverance. The grounding comes in v 15.</p>', '15': "<p>YHWH grounds the promise with his covenant name and his power over the sea (which churns at his command). The title LORD of hosts (<em>YHWH tsvaot</em>) — the commander of heaven's armies — reinforces that the power releasing the prisoner is the same power that created and governs the cosmos.</p>", '16': "<p>YHWH has put his words in the mouth of the servant/Zion figure and covered them with his hand. The act of setting the heavens in place and laying the foundations of the earth is attributed directly to YHWH speaking to and through this figure. The verse fuses the servant's vocation — YHWH's mouthpiece — with YHWH's cosmic creative acts, anticipating the <em>my word shall accomplish</em> of 55:11.</p>", '17': "<p>Jerusalem is called to rouse herself — she has drunk the cup of YHWH's wrath to the dregs. The cup-of-wrath image is vivid: she staggered through judgment. Now the call is to stand up, because the cup is about to be removed (v 22). The reversal of the wrath-cup is the dramatic arc that vv 17-23 unfold.</p>", '18': '<p>Among all the children Jerusalem bore and raised, none can lead her by the hand. The desolation of leadership — no guide, no comforter (v 19) — is the specific wound YHWH has allowed. This paves the way for YHWH himself to become the comforter and guide (v 12; 40:1).</p>', '19': '<p>Two paired calamities: devastation-and-ruin (the physical destruction of the city), famine-and-sword (the death of its people). No one mourns with her; no one comforts her. The rhetorical question — who will console you? — prepares the answer: only YHWH (v 12).</p>', '20': "<p>Jerusalem's sons have collapsed, lying at every street corner like an antelope in a net — exhausted, trapped, full of YHWH's wrath and his rebuke. The animal-in-a-net image conveys helplessness without hope of self-rescue. The deliverance must come entirely from outside.</p>", '21': '<p>A direct address to those who are suffering, who are drunk but not from wine — drunk from the cup of wrath (v 17), not from literal intoxication. The verse sets up the climactic promise of vv 22-23.</p>', '22': '<p>YHWH — your Lord, your God, who contends (<em>shaphat</em>/defend the case, disp 2) for his people — announces the removal of the cup. The title sequence is weighty: <em>adonai</em> (sovereign Lord) + <em>YHWH</em> (covenant name) + <em>elohayikh</em> (your God) + <em>yarib ammo</em> (who argues the legal case for his people). The contending God takes up the legal case of his people against their oppressors and wins it by taking the cup from their hand.</p>', '23': "<p>YHWH will give the cup to the tormentors — those who forced Jerusalem to lie down so they could walk over her. The reversal is complete: humiliation becomes the oppressors' lot. The cup-transfer is not personal vindictiveness but the restoration of right order: the one who caused unjust suffering bears it; the one who suffered unjustly is freed.</p>"}, '52': {'3': '<p>YHWH grounds the promise of redemption with a paradox: you were sold for nothing, and without silver you will be redeemed. Because the exile was not a legitimate sale — Babylon received nothing of real value, only YHWH permitted the transfer for discipline — there is no ransom price to be paid to Babylon. YHWH redeems his people not by paying Babylon off but by exercising his sovereign authority. This will become the pattern of the costless-yet-costly redemption of the Servant (53:4-6).</p>', '4': '<p>Two paradigmatic oppressions: Egypt (voluntary sojourn, then slavery) and Assyria (forced conquest, for nothing). In both cases YHWH ultimately intervened. The point is that YHWH has precedent for liberating his people from great powers — Babylon is simply the latest instance.</p>', '5': "<p>YHWH asks what stake he has in the current situation. His people are taken for nothing, their rulers howl with contempt, and his name is blasphemed. The blasphemy of YHWH's name among the nations is the trigger for action. YHWH's honor and his people's redemption are bound together.</p>", '6': '<p>Therefore my people will know my name — the exodus pattern: YHWH reveals his name through his acts of deliverance (cf. Exod 6:7). On that day they will know that I am the one who says, <em>Hineni</em> — Here I am. The self-disclosure formula is the same YHWH used at the burning bush and with the servant. Knowing the name means knowing the character revealed through act.</p>', '7': "<p>The herald's feet are beautiful (<em>navu</em>) on the mountains — the messenger's body is praised because his message is so good. Four parallel terms: good news (<em>mevaser</em>), <em>shalom</em> (peace, disp 2), good (<em>tov</em>), salvation (<em>yeshuah</em>). The climax: your God reigns (<em>malak elohayikh</em> — <em>melek</em>/king, disp 2). This is the enthronement announcement: YHWH has assumed his royal rule. Paul quotes this verse in Rom 10:15 as the pattern of gospel proclamation; the NT identifies the herald-feet with those who proclaim the Messiah's kingship. <em>Shalom</em> is not mere cessation of hostility but the comprehensive wellbeing of covenant life fully restored.</p>", '8': "<p>The watchmen of Zion raise their voices in united shout because they see eye to eye when YHWH returns to Zion. The watchman's job is to first sight the returning king; their unanimous rejoicing signals that the report is confirmed and unambiguous. The return of YHWH to Zion is the goal of the entire movement begun at 40:1.</p>", '9': '<p>Even the ruins of Jerusalem are commanded to burst into singing — inanimate rubble participates in the restoration. The ground: YHWH has comforted (<em>niham</em>) his people and redeemed Jerusalem. Comfort and redemption are the double foundation that the whole of chapters 40-55 has been building toward.</p>', '10': "<p>YHWH has bared his holy arm — made it visible, unsheathed his power — before all nations. The <em>qodesh</em>/holy arm (holiness, disp 2): the manifestation of YHWH's saving power is simultaneously the revelation of his holiness. All ends of the earth will see YHWH's salvation. The universal scope means Israel's redemption is the vehicle for worldwide revelation of who YHWH is.</p>", '11': "<p>The call to depart Babylon: Leave! Touch nothing unclean! The priestly logic — those who carry YHWH's vessels must be purified — echoes the Levitical purity of the wilderness tabernacle. The exilic priests will lead the return in a processional that is simultaneously an act of worship. The departure is both political liberation and cultic consecration.</p>", '12': '<p>You will not leave in a hurry or flee in panic — contrast with the original Exodus departure, which was hasty (Exod 12:11). The new exodus will be ordered, majestic, YHWH himself going before and also serving as rear guard. The rearguard imagery (cf. 58:8) shows YHWH encircling his people with protective presence, not merely leading from the front.</p>', '13': "<p>The Servant Song introduction: See, my servant will act wisely (<em>yaskil</em>); he will be raised, lifted up, and highly exalted. The triple vertical vocabulary — raised, lifted up, exalted — uses language reserved for YHWH's own glory (cf. 6:1). The Servant will share YHWH's exaltation status. The movement of the song: exaltation announcement (v 13), then the scandal of disfigurement (vv 14-15), into the Servant's suffering and vindication (53:1-12), and finally return to exaltation (53:12). <em>Yaskil</em> (wise/prudent) describes purposeful, covenant-faithful action that succeeds.</p>", '14': "<p>The counterpoint to exaltation: many were appalled at him because his appearance was so disfigured beyond any human likeness. The disfigurement is described in the strongest possible terms — beyond human. This prepares the reader for the Servant's suffering (53:2-9) while holding the exaltation (v 13) in tension: the same figure who will be lifted up is the one so marred that people turn away.</p>", '15': "<p>So he will sprinkle many nations — the verb <em>nazah</em> (sprinkle) is priestly, used of blood-sprinkling for purification and atonement (Lev 4, 14, 16). Kings will be struck silent before him, seeing what they had not been told, understanding what they had not heard. The reversal: those appalled (v 14) become those who comprehend and are silenced before the Servant's exaltation. Paul echoes this in Rom 15:21 as the pattern of Gentile gospel reception.</p>"}, '53': {'1': "<p>Who has believed what we proclaimed? — the opening question of the fourth Servant Song. <em>Aman</em> (believe/trust, disp 2): to believe the report is to entrust oneself to the message's truthfulness and to the one it describes. The question implies that the report is not self-evidently persuasive — the Servant's manner does not commend itself to natural observation (v 2). The arm of the LORD links back to 51:5, 9; 52:10: the same redemptive power the exiles prayed for has been revealed — but in a form that was not expected. Paul quotes this verse in Rom 10:16 to explain Israel's unbelief at the gospel proclamation.</p>", '2': "<p>The Servant's origins: like a tender shoot from dry soil, no attractive form or majesty to draw attention. The dry soil and absence of beauty are deliberate anti-messianic markers — this figure does not fit the kingly warrior expectation. The commentary of John 1:46 (Can anything good come out of Nazareth?) and 1 Cor 1:23 (a stumbling block to Jews and folly to Gentiles) inhabit exactly this gap between expectation and reality.</p>", '3': "<p>The Servant is despised and rejected by people — a man who <em>yada</em> suffering (knew/was familiar with, disp 2). <em>Yada</em> here is experiential knowledge — intimate acquaintance with suffering, not mere observation. Like one from whom people hide their faces: the Servant's suffering is so severe that observers avert their eyes. We held him of no account — the communal speakers confess that they dismissed the Servant. This verse is the turning point where the speakers recognize their error.</p>", '4': "<p>Yet he was the one who took up our sicknesses and carried our pain. The contrast (<em>aken</em> — surely, yet) corrects the misreading: we thought he was being struck by God; in fact he was bearing ours. The taking-up vocabulary (<em>nasa</em>) is the same used for the scapegoat (Lev 16:22) and for priestly sin-bearing. Matthew quotes this verse (Matt 8:17) applying it to Jesus' healing ministry — the bearing of infirmities was the pattern of the Servant's entire ministry, not only his death.</p>", '5': '<p>He was pierced because of our transgressions, crushed because of our iniquities. The preposition is <em>min</em> + cause — his wounds are directly caused by our sin. The punishment that brought us <em>shalom</em> was upon him (<em>shalom</em>, disp 2): the chastisement (<em>musar</em>) that produces comprehensive wellbeing for us fell on him. By his wounds we are healed — the healing is grounded in the wounding. <em>Shalom</em> here is not merely peace as reconciliation but the full restoration of every dimension of life that was broken by sin. This is the most direct substitutionary statement in the Hebrew Bible; the NT applies it to the atonement at 1 Pet 2:24.</p>', '6': "<p>The communal confession: we all went astray like sheep; each turned to his own way. The sheep-going-astray image is universal and specific — the aimless wandering of the sheep who has no shepherd. The LORD laid on him the iniquity of us all — the active subject is YHWH, and the verb (<em>hifgiya</em>) means to cause to meet, to lay upon. The cosmic transaction is not the Servant's unilateral act but YHWH's purposeful placing of the community's collective guilt upon the Servant. This is the heart of substitutionary atonement.</p>", '7': "<p>The Servant's silence under oppression: he never opened his mouth. The doubled simile — lamb to slaughter, sheep before shearers — emphasizes absolute non-resistance. This is not weakness but purposeful submission to the role YHWH has assigned. Philip uses this verse in Acts 8:32-35 to explain the gospel to the Ethiopian eunuch; the early church consistently read the silence as Jesus' silence before Pilate (Mark 14:61, 15:5).</p>", '8': "<p>By a perversion of justice he was taken away — a legal inversion; the just one is condemned by unjust process. Who gave any thought to his fate? — his generation did not consider the meaning of what was happening. He was cut off from the land of the living — the language of violent premature death. Because of my people's transgression, the stroke fell on him — again the substitutionary logic: the stroke aimed at the transgressors meets the Servant instead.</p>", '9': "<p>He was assigned a grave among the wicked, yet his burial was with the rich. The double burial notice corresponds to the paradox of the entire song: the Servant ends where he does not deserve to end because his death was not for his own sins. He had done no violence, and no deceit was in his mouth — the Servant's moral innocence is explicit. The NT applies v 9 to Jesus' burial in Joseph of Arimathea's tomb (Matt 27:57-60).</p>", '10': "<p>Yet it was the LORD's will to crush him and make him suffer. The crushing is YHWH's purposive act, not merely permitted tragedy. When his <em>nefesh</em> (soul/life, disp 3) is given as a guilt offering (<em>asham</em>) — the <em>asham</em> is the reparation offering of Lev 5-6, given when one has incurred liability by trespassing on what belongs to another. The Servant's <em>nefesh</em> — his whole self, his life — is the reparation that settles the debt. The result: he will see offspring, prolong his days, and YHWH's purpose will prosper. Life follows the <em>asham</em>-death; vindication follows crushing.</p>", '11': "<p>Out of the anguish of his <em>nefesh</em> (soul, disp 3) he will see and be satisfied. The sight after suffering — the Servant sees the result of his <em>asham</em> and is content. By his knowledge my righteous servant will make many righteous — <em>yada</em> knowledge (disp 2): the Servant's experiential knowing, the same knowing-suffering of v 3, is now the instrument of justification. He bears their iniquities (<em>yisbol</em> — same root as v 4). The many who are made righteous are the counterpart of the we all who went astray (v 6).</p>", '12': "<p>Therefore I will give him a portion among the great, and he will share the plunder with the strong — because he poured out his <em>nefesh</em> (soul, disp 3) to death and was counted among the transgressors. Three grounds for the vindication-reward: he poured out his <em>nefesh</em>, he was numbered with rebels, he bore the sin of many and made intercession for transgressors. The intercession continues after the atoning death — the Servant's advocacy does not end at the cross. Luke 22:37 quotes this verse as Jesus' own self-interpretation at the Last Supper.</p>"}, '54': {'1': "<p>The barren woman who never gave birth is called to sing — the reversal of the deepest human shame in the ancient world. The children of the desolate woman will be more than the children of the one who is married. The barren-Zion metaphor follows directly from the Servant's death and vindication (53:10-12): the offspring the Servant sees after his <em>asham</em>-death are the children of barren Zion's abundance. Paul quotes this verse in Gal 4:27 as the freedom of the heavenly Jerusalem — the mother of those born of promise, not of law.</p>", '2': '<p>Enlarge the tent — the nomadic image of a family whose expansion requires a bigger dwelling. Zion must prepare for growth she cannot yet see. Do not hold back, lengthen your cords, strengthen your pegs — the structural details of tent-expansion make the command concrete. The faith called for is to act on the promise before seeing the evidence.</p>', '3': "<p>You will spread out to the right and to the left; your descendants will reclaim nations and resettle desolate cities. The expansion language uses the same vocabulary as the Abrahamic land promises (Gen 28:14). Zion's multiplication fulfills the patriarchal covenant — another link in the chain from Abraham (51:2) through the Servant to the restored community.</p>", '4': '<p>Do not be afraid; you will not be put to shame. For you will forget the shame of your youth and remember no more the disgrace of your widowhood. Two past shames: the youth (Egypt, the formative humiliation) and the widowhood (the exile, the loss of the divine husband). Both are swallowed up in the new marriage YHWH announces in v 5.</p>', '5': '<p>Your Maker is your husband — the two most comprehensive divine titles collapse into the marriage metaphor. YHWH of hosts (creator of the cosmos, commander of its armies), the Holy One of Israel (the utterly transcendent one), the God of the whole earth — all these describe the one who is entering marital covenant with Zion. The shock of the verse is that the incomprehensibly great God is simultaneously the intimate covenant partner of a ruined city.</p>', '6': "<p>The LORD has called you back like a wife who was abandoned and heartbroken — the exile is reread as marital estrangement, not divorce. The wife of one's youth is the first and most beloved; the call back is a restoration to the original relationship's fullness, not merely a legal reconciliation.</p>", '7': "<p>For a brief moment I abandoned you, but with great compassion (<em>rahamim</em>) I will bring you back. The ratio is important: exile is a brief moment; return is great compassion. The quantitative imbalance mirrors the Servant's logic (53:4-6): a bounded act of suffering produces unbounded redemptive result. <em>Rahamim</em> (compassion) shares its root with <em>rehem</em> (womb) — this is maternal-gut compassion, the most visceral human tenderness.</p>", '8': "<p>In a surge of anger I hid my face from you for a moment, but with <em>hesed olam</em> (everlasting covenant love, <em>hesed</em> disp 4, <em>olam</em> disp 3) I will have compassion on you. <em>Hesed</em> is the covenant-loyalty love grounded in the covenant YHWH initiated, not in the worthiness of its object. It is everlasting (<em>olam</em>) — not subject to the fluctuations of anger. The anger was real but momentary; the <em>hesed</em> is constitutive of YHWH's character and therefore permanent. The contrast <em>olam</em>-hesed vs. moment-anger is the theological heart of this passage.</p>", '9': "<p>The Noah covenant becomes the interpretive framework: just as YHWH swore that the waters of Noah would never again cover the earth — and has kept that oath — so he swears never again to be angry with or rebuke Zion. The Noah oath is the precedent for the Zion oath. Both are unconditional, unilateral divine commitments grounded in YHWH's own character, not in human performance.</p>", '10': "<p>Though the mountains should move and the hills be shaken, my <em>hesed</em> (covenant love, disp 4) will not move from you, and my covenant of <em>shalom</em> (<em>berit shalom</em>, <em>berit</em> disp 3, <em>shalom</em> disp 2) will not be shaken. Mountains and hills — the most geologically stable features of the ancient world — become the measure of divine commitment: even if they move, YHWH's covenant will not. The covenant of peace bundles two of the highest-disp terms: the binding formal agreement (<em>berit</em>) and the comprehensive wellbeing (<em>shalom</em>) that is both the content and the goal of the covenant.</p>", '11': "<p>Zion is addressed directly as afflicted city, tossed by storms and without comfort — the same desolate figure as the barren woman of v 1, now about to be rebuilt with precious stones. The gemstone-rebuilding of vv 11-12 is a reversal of the rubble of 51:17-20: the same city lying in ruins will be refounded in splendor. The materials (sapphires, rubies, sparkling jewels, precious stones) recall both the gemstones of the high priest's breastplate and the foundation stones of the new Jerusalem (Rev 21:19-20).</p>", '12': '<p>The architectural specifics — towers, gates, walls — all of precious stones. The gate of sparkling jewels is the point of entry into the city; the precious-stone wall is what protects it. Beauty and security are unified in the rebuilt Zion. Revelation 21 draws directly on this imagery for the new Jerusalem.</p>', '13': "<p>All your children will be taught by the LORD, and great will be their <em>shalom</em> (peace, disp 2). The promised outcome of the covenant of <em>shalom</em> (v 10) is that all Zion's children receive divine instruction directly. This is the new covenant of Jer 31:33-34 — no longer needing to teach neighbor or brother, for all will know YHWH. Jesus quotes this verse in John 6:45 (they will all be taught by God) as the condition of coming to him.</p>", '14': "<p>You will be established in <em>tsedaqah</em> (righteousness, disp 3); you will be far from oppression and will not fear. The community's foundation shifts from precarious human power to YHWH's righteousness — the same <em>tsedaqah</em> that the exiles were called to pursue (51:1) and that YHWH was about to enact (51:5). When YHWH's righteousness is the foundation, terror cannot take root.</p>", '15': "<p>If anyone attacks you, it is not my doing — YHWH disavows the coming attacks before they happen. The threat from outsiders will ultimately fail: whoever assembles against you will fall before you. The passive falling is YHWH's active judgment; the city needs only stand in its righteousness.</p>", '16': "<p>YHWH claims credit for creating the blacksmith who forges weapons and the destroyer who wields them. This is the most totalizing sovereignty claim in the passage: the one who makes the weapons and the one who deploys them are both YHWH's creatures. He is not threatened by the weapons made against Zion because he created their makers.</p>", '17': "<p>No weapon formed against you will succeed, and every tongue that accuses you in court you will refute. The legal and military threats are both covered. This is the inheritance (<em>nahalah</em>) of the servants of YHWH, and their <em>tsedaqah</em> (righteousness, disp 3) is from me. The closing verse reframes the entire chapter: safety, vindication, and righteousness are not Zion's own achievement but her covenant inheritance — received from YHWH, declared by him. <em>Nahalah</em> (inheritance) is the Promised Land vocabulary applied to the eschatological community.</p>"}, '55': {'1': '<p>The invitation to all who are thirsty opens without qualification — not all of Israel but all who recognize their need. Come to the waters; come, buy and eat; buy wine and milk without money and without price. The economic paradox — buy without money — strips away the normal mechanism of exchange and declares that what YHWH offers is beyond market logic. Thirst and hunger are the condition of exile; the invitation offers exactly what exile cannot provide. The whole <em>nefesh</em> (soul, disp 3) — the whole self — is what thirsts, and the whole self is what YHWH feeds. Jesus draws on this imagery in John 7:37 and Rev 22:17.</p>', '2': "<p>Why do you spend money on what is not bread, and your wages on what does not satisfy? The question diagnoses the exile's futile labor: working for Babylon, acquiring what cannot feed the soul. Listen carefully to me and eat what is good; let your <em>nefesh</em> (soul, disp 3) delight in richness. The alternative to dissatisfying toil is to incline the ear to YHWH — hearing is the mode of access to the banquet. This is the economics of grace: the satisfying food is received by attention, not by labor.</p>", '3': "<p>Incline your ear and come to me; hear, and you will live; and I will make an everlasting covenant (<em>berit olam</em>, <em>berit</em> disp 3, <em>olam</em> disp 3) with you — my reliable <em>hesed</em> (covenant love, disp 4) promised to David. The Davidic covenant — the unconditional promise of 2 Sam 7 — is the model and the content of what YHWH now extends to the whole community. The individual king's covenant is democratized: all who hear and come participate in the Davidic promises. <em>Berit olam</em> and <em>hesed David</em> are the two deepest covenant terms, stacked together to name what YHWH is offering.</p>", '4': '<p>David was made a witness, leader, and commander for the peoples — his role was never merely national. The Davidic covenant always had a universal scope (Ps 2, 72). By democratizing the Davidic covenant (v 3), YHWH is extending the universal witness-function to the whole restored community.</p>', '5': "<p>You will summon a nation you did not know, and a nation that did not know you will run to you, because of the LORD your God, the Holy One of Israel. The expansion echoes 54:3 and the Abrahamic promise: Zion becomes the center to which nations stream. The motivation is entirely YHWH's initiative — the nations are drawn not by Israel's attractiveness but by YHWH's glory revealed through Israel.</p>", '6': '<p>Seek the LORD while he may be found; call on him while he is near. The urgency is temporal — there is a window. This is not simply a timeless invitation but a kairos-moment call. The exilic community stands at the turning point when YHWH is near in the sense that the announcement of return (52:7-12) has been made; delay means missing the moment of return.</p>', '7': "<p>Let the wicked forsake his way and the unrighteous man his thoughts; let him return to the LORD, who will have mercy (<em>rahem</em> — womb-compassion), and to our God, who will abundantly pardon. The return YHWH requires is not first geographic (return from Babylon) but moral (forsake wickedness). The pardon is abundant — <em>yarbeh lisloak</em>, literally will multiply to pardon. YHWH's forgiveness is not reluctant or minimal but extravagant. The double mercy (<em>rahem</em> and pardon) grounds the call to return.</p>", '8': "<p>For my thoughts are not your thoughts, and your ways are not my ways. This is the foundation of the abundant-pardon verse: YHWH pardons more than humans think possible because he thinks and acts on a different plane. The for connects the limitless pardon (v 7) to the limitless otherness of YHWH's mind (vv 8-9). This is also the ground for the sovereign initiative of vv 1-6: YHWH invites, acts, and accomplishes in ways that transcend human calculation.</p>", '9': "<p>As the heavens are higher than the earth, so are my ways higher than your ways and my thoughts higher than your thoughts. The spatial image gives scale to the qualitative difference. This is not skepticism about human reason but an assertion that YHWH's thoughts and ways belong to a different order of magnitude. The invitation to seek the LORD (v 6) is therefore both urgent and humble: we seek one whose ways we cannot anticipate or control.</p>", '10': "<p>The word of YHWH is compared to rain and snow that come down from heaven — they do not return until they have accomplished their purpose: watered the earth, made it sprout, given seed and bread. The hydrological cycle becomes a metaphor for the efficacy of divine speech: just as precipitation achieves its agricultural purpose without fail, so YHWH's word achieves its purpose without fail.</p>", '11': '<p>So shall my word be that goes out from my mouth; it shall not return to me empty, but it shall accomplish what I purpose and succeed in the thing for which I sent it. The word sent here is the entire promise-complex of chapters 40-55: comfort, return, Servant, covenant. This verse is the retroactive authorization of everything proclaimed in these chapters. The word does not merely describe what will happen; it is itself the agent that brings it about. John 1:1-3 and Heb 1:2-3 inhabit the logic of this verse in their identification of the eternal Word as the agent of creation and redemption.</p>', '12': "<p>For you will go out with joy and be led forth in <em>shalom</em> (peace, disp 2). The exodus-language: go out (<em>yetse'u</em>) and be led forth (<em>tuvalun</em>) are exodus verbs. But the second exodus is marked by joy and <em>shalom</em> rather than haste and fear (52:12). The mountains and hills shall burst into song before you, and all the trees of the field shall clap their hands — creation joins the processional, extending the singing-ruins of 52:9 to the entire natural world. The new exodus is a cosmic event, not merely a political one.</p>", '13': "<p>Instead of the thorn the cypress shall come up, and instead of the brier the myrtle shall come up. The transformation of the wilderness through which the exiles return is a sign (<em>ot</em>) and an everlasting memorial (<em>olam</em>, disp 3) that will not be cut off. The sign function of the transformed landscape: creation's changed state is a standing testimony to what YHWH has done. The covenant of <em>shalom</em> (54:10) and the everlasting covenant (55:3) are written in the renewed creation as well as in the community's life.</p>"}}

def main():
    data = load_comm('mkt-original', 'isaiah')
    merge_comm(data, ISAIAH)
    chs = sorted(data.keys(), key=lambda x: int(x))
    total_v = sum(len(data[c]) for c in chs)
    print(f'Isaiah original: {len(chs)} chapters, {total_v} verses')
    save_comm('mkt-original', 'isaiah', data)

if __name__ == '__main__':
    main()
